from pydantic_ai import Agent
from vex_sdk import monitor

@monitor('validator_rejection_rate')
def detect_validator_failures(agent: Agent):
    metrics = agent.metrics
    rejection_rate = metrics.get('validation_errors', 0) / metrics.get('total_calls', 1)
    return {
        'rejection_rate': rejection_rate,
        'threshold_breached': rejection_rate > 0.3,
        'last_errors': metrics.get('recent_errors', [])
    }

def detect_retry_loops(agent):
    from collections import Counter
    error_traces = agent.traces[-100:]
    error_types = [trace.error for trace in error_traces if trace.error]

    error_counts = Counter(error_types)
    persistent_loops = {
        err_type: count 
        for err_type, count in error_counts.items() 
        if count > 3
    }

    return {
        'has_loops': len(persistent_loops) > 0,
        'loops': persistent_loops,
        'retry_waste_pct': len(error_traces) / agent.total_calls
    }

def scan_streaming_failures(agent):
    stream_traces = [t for t in agent.traces if t.is_streaming]
    failures = []
    for trace in stream_traces:
        if trace.partial_validations > 0 and not trace.final_success:
            failures.append({
                'trace_id': trace.id,
                'partial_count': trace.partial_validations,
                'final_error': trace.final_error
            })
    return {
        'streaming_failure_rate': len(failures) / len(stream_traces),
        'critical_failures': failures[:5]
    }

