from pydantic_ai import Agent
from vex_sdk import ResultValidator
from pydantic import BaseModel, field_validator

class LenientOutput(BaseModel):
    @field_validator('*', mode='before')
    @classmethod
    def flexible_parsing(cls, v, info):
        if isinstance(v, str) and info.field_name in ['reasoning', 'notes']:
            return v.strip()
        return v

class VexValidator(ResultValidator):
    def validate(self, output: dict) -> bool:
        try:
            LenientOutput.model_validate(output)
            return True
        except:
            # Fallback to semantic validation
            return 'error' not in output and len(output) > 0

agent = Agent(..., result_validator=VexValidator())

from pydantic_ai import tool, Agent
from typing import Annotated

@tool
def safe_tool_call(
    func_name: str,
    *args,
    __vex_context__: Annotated[dict, 'Current agent context'] = None,
    **kwargs
):
    """Wrapper that preserves context in nested calls"""
    if __vex_context__:
        kwargs['user_context'] = __vex_context__.get('user_context')

    # Execute actual tool
    tool_func = getattr(tools, func_name)
    return tool_func(*args, **kwargs)

agent = Agent(tools=[safe_tool_call])

from pydantic_ai import StreamingAgent
from typing import Iterator

class ProgressiveValidator:
    def __init__(self, model):
        self.model = model
        self.buffer = {}

    def validate_chunk(self, chunk: dict) -> Iterator[dict]:
        self.buffer.update(chunk)
        try:
            # Try partial validation
            validated = self.model.model_validate(self.buffer)
            yield {'status': 'valid', 'data': validated.model_dump()}
        except:
            yield {'status': 'partial', 'buffer_size': len(self.buffer)}

agent = StreamingAgent(
    result_validator=ProgressiveValidator(LenientOutput)
)
